let panier = [];

// =======================
// AJOUT PRODUIT (AUTO)
// =======================
function ajouter(nom, prix) {
    let restoElement = document.getElementById("restaurant");
    let type = restoElement ? "restaurant" : "market";

    let exist = panier.find(item =>
        item.nom === nom && item.prix === prix && item.type === type
    );

    if (exist) {
        exist.quantite += 1;
    } else {
        panier.push({nom, prix, quantite: 1, type});
    }

    updatePanier();
    animationpanier();
    messagePanier();
}

// =======================
// FERMER PANIER SI CLICK
// =======================
document.addEventListener("click", function(e){
    let pc = document.getElementById("panier-container");
    let icon = document.querySelector(".panier-icon");

    if (pc && icon && !pc.contains(e.target) && !icon.contains(e.target)) {
        pc.style.display = "none";
    }
});

// =======================
// VIDER PANIER
// =======================
function viderpanier() {
    panier = [];
    updatePanier();
    localStorage.removeItem("panierhavenix");
}

// =======================
// ANIMATION PANIER
// =======================
function animationpanier() {
    let icon = document.querySelector(".panier-icon img");
    if (!icon) return;

    icon.classList.add("animate");
    setTimeout(() => icon.classList.remove("animate"), 300);
}

// =======================
// MESSAGE AJOUT
// =======================
function messagePanier() {
    let msg = document.getElementById("message-panier");
    if (!msg) return;

    msg.style.display = "block";
    setTimeout(() => msg.style.display = "none", 1500);
}

// =======================
// UPDATE PANIER
// =======================
function updatePanier(){
    let compteur = document.getElementById("compteur");
    let list = document.getElementById("panier-list");
    let totalDiv = document.getElementById("total");

    if (!compteur || !list || !totalDiv) return;

    compteur.innerText = panier.reduce((a, b) => a + b.quantite, 0);

    list.innerHTML = "";

    let total = 0;

    panier.forEach((item, index) => {
        total += item.prix * item.quantite;

        let div = document.createElement("div");
        div.classList.add("panier-item");

        div.innerHTML = `
            <span>${item.nom} - ${item.prix} F x ${item.quantite}</span>
            <button onclick="supprimerUne(${index})">Supprimer</button>
        `;

        list.appendChild(div);
    });

    totalDiv.innerText = "Total : " + total + " F";

    localStorage.setItem("panierhavenix", JSON.stringify(panier));
}

// =======================
// SUPPRIMER ITEM
// =======================
function supprimerUne(index) {
    if (panier[index].quantite > 1) {
        panier[index].quantite--;
    } else {
        panier.splice(index, 1);
    }
    updatePanier();
}

// =======================
// OUVRIR / FERMER PANIER
// =======================
function togglePanier() {
    let pc = document.getElementById("panier-container");
    if (!pc) return;

    pc.style.display = (pc.style.display === "block") ? "none" : "block";
}

// =======================
// MENU HAMBURGER
// =======================
function toggleMenu() {
    const menu = document.getElementById("menu");
    if (!menu) return;

    menu.style.display = (menu.style.display === "flex") ? "none" : "flex";
}

// =======================
// AJOUT JUS / FRUITS
// =======================
function commanderjus(idSelect, nomProduit) {
    let select = document.getElementById(idSelect);
    if (!select) return;

    let texte = select.options[select.selectedIndex].text;
    let prix = Number(select.value) || 0;

    let nom = nomProduit + " - " + texte;

    ajouter(nom, prix);
}

// =======================
// AJOUT PLAT RESTAURANT
// =======================
function commanderPlat(idPrix, idAcc, idExtra, nomPlat, idtype) {
    let selectPrix = document.getElementById(idPrix);
    if (!selectPrix) return;

    let prixBase = Number(selectPrix.value) || 0;
    let total = prixBase;

    let choixPrix = selectPrix.options[selectPrix.selectedIndex].text;

    let acc = "";
    let selectAcc = document.getElementById(idAcc);
    if (selectAcc && selectAcc.value !== "") {
        acc = selectAcc.value;
    }

    let extra = "";
    let prixExtra = 0;
    let selectExtra = document.getElementById(idExtra);

    if (selectExtra && selectExtra.value !== "0") {
        prixExtra = Number(selectExtra.value);
        extra = selectExtra.options[selectExtra.selectedIndex].text;
        total += prixExtra;
    }

    let nom = nomPlat + " - " + choixPrix;

    if (acc) nom += " + " + acc;
    if (extra) nom += " + " + extra;

    let inputDetail = document.getElementById(idtype);
    if (inputDetail && inputDetail.value !== "") {
        nom += " (" + inputDetail.value + ")";
    }

    ajouter(nom, total);
}

// =======================
// WHATSAPP (VERIFICATION AVANT PAIEMENT)
// =======================
function EnvoyerWhatsApp() {
    let nomClient = document.getElementById("client-nom").value.trim();
    let numeroClient = document.getElementById("client-numero").value.trim();
    let localisation = document.getElementById("client-localisation").value.trim();

    if (nomClient === "" || numeroClient === "") {
        alert("Veuillez remplir votre nom et numéro");
        return;
    }

    if (panier.length === 0) {
        alert("Votre panier est vide");
        return;
    }

    // Sauvegarde
    localStorage.setItem("client_nom", nomClient);
    localStorage.setItem("client_numero", numeroClient);
    localStorage.setItem("client_localisation", localisation);

    let restoElement = document.getElementById("restaurant");
    let restaurant = restoElement ? restoElement.innerText : "";

    let message = "🛒 Commande Havenix CI Market\n\n";

    let total = 0;

    let plats = panier.filter(item => item.type === "restaurant");
    if (plats.length > 0) {
        message += "🍽️ " + restaurant + "\n";
        plats.forEach(item => {
            message += "➤ " + item.nom + "\n";
            message += "💵 " + item.prix + " F x " + item.quantite + "\n\n";
            total += item.prix * item.quantite;
        });
    }

    let produits = panier.filter(item => item.type === "market");
    if (produits.length > 0) {
        message += "🛒 Produits Market\n";
        produits.forEach(item => {
            message += "➤ " + item.nom + "\n";
            message += "💵 " + item.prix + " F x " + item.quantite + "\n\n";
            total += item.prix * item.quantite;
        });
    }

    let livraison = 1000;
    let totalFinal = total + livraison;

    message += "---------------------\n";
    message += "Livraison : " + livraison + " F\n";
    message += "Total estimé : " + totalFinal + " F\n\n";

    message += "👤 Client : " + nomClient + "\n";
    message += "📞 Numéro : " + numeroClient + "\n";

    if (localisation !== "") {
        message += "📍 Localisation : " + localisation + "\n";
    }

    // ✅ VERIFICATION AVANT PAIEMENT
    message += "\n====================\n";
    message += "⏳ Vérification de votre commande en cours...\n";
    message += "Nous confirmons la disponibilité avant paiement.\n";

    let numero = "2250798016927";
    window.open("https://wa.me/" + numero + "?text=" + encodeURIComponent(message));
}

// =======================
// CHARGEMENT AU DEMARRAGE
// =======================
window.onload = function() {

    let saved = localStorage.getItem("panierhavenix");
    if (saved) {
        panier = JSON.parse(saved);
        updatePanier();
    }

    // Restaurer infos client
    let nom = localStorage.getItem("client_nom");
    let numero = localStorage.getItem("client_numero");
    let localisation = localStorage.getItem("client_localisation");

    if (nom && document.getElementById("client-nom")) {
        document.getElementById("client-nom").value = nom;
    }

    if (numero && document.getElementById("client-numero")) {
        document.getElementById("client-numero").value = numero;
    }

    if (localisation && document.getElementById("client-localisation")) {
        document.getElementById("client-localisation").value = localisation;
    }

    // Sauvegarde automatique
    let inputNom = document.getElementById("client-nom");
    let inputNumero = document.getElementById("client-numero");
    let inputLocalisation = document.getElementById("client-localisation");

    if (inputNom) {
        inputNom.addEventListener("input", function() {
            localStorage.setItem("client_nom", inputNom.value);
        });
    }

    if (inputNumero) {
        inputNumero.addEventListener("input", function() {
            localStorage.setItem("client_numero", inputNumero.value);
        });
    }

    if (inputLocalisation) {
        inputLocalisation.addEventListener("input", function() {
            localStorage.setItem("client_localisation", inputLocalisation.value);
        });
    }
};
